"use client";

import { useMemo, useState, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { Tooltip } from "@/components/ui/tooltip";

const sizeClasses = {
  xs: "size-5 text-[9px]",
  sm: "size-6 text-[10px]",
  md: "size-8 text-xs",
  lg: "size-10 text-sm",
  xl: "size-12 text-base",
} as const;

export interface TokenLogoProps {
  /** Token image URL */
  src?: string | null;
  /** Token symbol, used for alt text and fallback initials */
  symbol?: string | null;
  /** Token name, used for alt text */
  name?: string | null;
  /** Token contract address, used as a fallback label */
  address?: string | null;
  /** Visual size. Default: md */
  size?: keyof typeof sizeClasses;
  /** Custom fallback content when the image is missing or fails */
  fallback?: ReactNode;
  /** Show an animated tooltip. Default: false */
  showTooltip?: boolean;
  /** Tooltip content. Defaults to name, symbol, then address. */
  tooltipContent?: ReactNode;
  /** Applied to the root wrapper */
  className?: string;
  /** Applied to the image */
  imageClassName?: string;
  /** Applied to the fallback */
  fallbackClassName?: string;
}

function getFallbackText({
  address,
  name,
  symbol,
}: Pick<TokenLogoProps, "address" | "name" | "symbol">) {
  if (symbol) return symbol.slice(0, 4).toUpperCase();
  if (name) return name.slice(0, 2).toUpperCase();
  if (address) return address.slice(2, 4).toUpperCase();
  return "?";
}

export function TokenLogo({
  src,
  symbol,
  name,
  address,
  size = "md",
  fallback,
  showTooltip = false,
  tooltipContent,
  className,
  imageClassName,
  fallbackClassName,
}: TokenLogoProps) {
  const [hasImageError, setHasImageError] = useState(false);
  const shouldShowImage = Boolean(src) && !hasImageError;

  const alt = useMemo(() => {
    if (name && symbol) return `${name} (${symbol})`;
    return name ?? symbol ?? address ?? "Token";
  }, [address, name, symbol]);

  const tooltip = tooltipContent ?? name ?? symbol ?? address;

  const logo = (
    <span
      className={cn(
        "relative inline-flex shrink-0 items-center justify-center overflow-hidden rounded-full border bg-muted font-medium text-muted-foreground",
        sizeClasses[size],
        className
      )}
    >
      {shouldShowImage ? (
        <img
          src={src ?? undefined}
          alt={alt}
          className={cn("size-full object-cover", imageClassName)}
          loading="lazy"
          decoding="async"
          referrerPolicy="no-referrer"
          onError={() => setHasImageError(true)}
        />
      ) : (
        <span className={cn("select-none", fallbackClassName)}>
          {fallback ?? getFallbackText({ address, name, symbol })}
        </span>
      )}
    </span>
  );

  if (!showTooltip) return logo;

  return <Tooltip content={tooltip}>{logo}</Tooltip>;
}

import { ArrowDownIcon, ArrowUpIcon, MinusIcon } from "lucide-react";
import { cn } from "@/lib/utils";
import type { ReactNode } from "react";

type PriceValue = number | string | null | undefined;
type Trend = "down" | "neutral" | "up";

const trendClasses = {
  down: "text-red-600 dark:text-red-400",
  neutral: "text-muted-foreground",
  up: "text-emerald-600 dark:text-emerald-400",
} as const;

export interface TokenPriceProps {
  /** Token price value */
  value: PriceValue;
  /** ISO 4217 currency code. Default: USD */
  currency?: string;
  /** Locale passed to Intl.NumberFormat */
  locale?: string;
  /** Use compact notation, e.g. $3.2K */
  compact?: boolean;
  /** Value shown when price is null, undefined, empty, or invalid. Default: -- */
  fallback?: ReactNode;
  /** Minimum fraction digits for the price */
  minimumFractionDigits?: number;
  /** Maximum fraction digits for the price */
  maximumFractionDigits?: number;
  /** 24h-style percentage change, e.g. -2.34 means -2.34% */
  change?: number | null;
  /** Override the derived change direction */
  trend?: Trend;
  /** Show trend icon before the change. Default: true */
  showChangeIcon?: boolean;
  /** Fraction digits for the change value. Default: 2 */
  changeFractionDigits?: number;
  /** Hide the plus sign for positive changes. Default: false */
  hidePositiveSign?: boolean;
  /** Applied to the root wrapper */
  className?: string;
  /** Applied to the formatted price */
  priceClassName?: string;
  /** Applied to the change badge */
  changeClassName?: string;
}

function parsePriceValue(value: PriceValue) {
  if (typeof value === "number") return Number.isFinite(value) ? value : null;
  if (typeof value === "string" && value.trim() !== "") {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : null;
  }
  return null;
}

function getMaximumFractionDigits(value: number) {
  const abs = Math.abs(value);
  if (abs >= 1) return 2;
  if (abs >= 0.01) return 4;
  return 6;
}

function formatPrice({
  compact,
  currency,
  locale,
  maximumFractionDigits,
  minimumFractionDigits,
  value,
}: {
  compact: boolean;
  currency: string;
  locale?: string;
  maximumFractionDigits?: number;
  minimumFractionDigits?: number;
  value: number;
}) {
  return new Intl.NumberFormat(locale, {
    style: "currency",
    currency,
    currencyDisplay: "narrowSymbol",
    notation: compact ? "compact" : "standard",
    minimumFractionDigits,
    maximumFractionDigits:
      maximumFractionDigits ?? getMaximumFractionDigits(value),
  }).format(value);
}

function getTrend(change?: number | null): Trend {
  if (!change) return "neutral";
  return change > 0 ? "up" : "down";
}

function formatChange(
  change: number,
  fractionDigits: number,
  hidePositiveSign: boolean
) {
  const sign = change > 0 && !hidePositiveSign ? "+" : "";
  return `${sign}${change.toFixed(fractionDigits)}%`;
}

function TrendIcon({ trend }: { trend: Trend }) {
  if (trend === "up") return <ArrowUpIcon className="size-3" />;
  if (trend === "down") return <ArrowDownIcon className="size-3" />;
  return <MinusIcon className="size-3" />;
}

export function TokenPrice({
  value,
  currency = "USD",
  locale,
  compact = false,
  fallback = "--",
  minimumFractionDigits,
  maximumFractionDigits,
  change,
  trend,
  showChangeIcon = true,
  changeFractionDigits = 2,
  hidePositiveSign = false,
  className,
  priceClassName,
  changeClassName,
}: TokenPriceProps) {
  const parsedValue = parsePriceValue(value);
  const shouldShowChange = typeof change === "number" && Number.isFinite(change);
  const derivedTrend = trend ?? getTrend(change);

  return (
    <span className={cn("inline-flex items-center gap-2", className)}>
      <span className={cn("font-mono tabular-nums", priceClassName)}>
        {parsedValue === null
          ? fallback
          : formatPrice({
              compact,
              currency,
              locale,
              maximumFractionDigits,
              minimumFractionDigits,
              value: parsedValue,
            })}
      </span>

      {shouldShowChange && (
        <span
          className={cn(
            "inline-flex items-center gap-0.5 font-mono text-xs tabular-nums",
            trendClasses[derivedTrend],
            changeClassName
          )}
        >
          {showChangeIcon && <TrendIcon trend={derivedTrend} />}
          {formatChange(change, changeFractionDigits, hidePositiveSign)}
        </span>
      )}
    </span>
  );
}

import { cn } from "@/lib/utils";
import { TokenLogo, type TokenLogoProps } from "./token-logo";
import { TokenPrice, type TokenPriceProps } from "./token-price";
import type { ReactNode } from "react";

type BalanceValue = number | string | null | undefined;

export interface TokenBalanceProps {
  /** Token amount */
  amount: BalanceValue;
  /** Token symbol, shown after the amount */
  symbol?: string | null;
  /** Token name, used for logo alt text */
  name?: string | null;
  /** Token image URL */
  src?: string | null;
  /** Token contract address, used as a fallback label */
  address?: string | null;
  /** Fiat value for the token balance */
  fiatValue?: TokenPriceProps["value"];
  /** Fiat value percentage change */
  change?: TokenPriceProps["change"];
  /** Show the token logo. Default: true */
  showLogo?: boolean;
  /** Show fiat value when provided. Default: true */
  showFiatValue?: boolean;
  /** Locale passed to Intl.NumberFormat */
  locale?: string;
  /** Maximum fraction digits for the token amount. Default: 4 */
  maximumFractionDigits?: number;
  /** Minimum fraction digits for the token amount */
  minimumFractionDigits?: number;
  /** Value shown when amount is null, undefined, empty, or invalid. Default: -- */
  fallback?: ReactNode;
  /** Props passed to TokenLogo */
  logoProps?: Partial<TokenLogoProps>;
  /** Props passed to TokenPrice */
  priceProps?: Partial<TokenPriceProps>;
  /** Applied to the root wrapper */
  className?: string;
  /** Applied to the amount line */
  amountClassName?: string;
  /** Applied to the fiat value line */
  fiatClassName?: string;
}

function parseBalanceValue(value: BalanceValue) {
  if (typeof value === "number") return Number.isFinite(value) ? value : null;
  if (typeof value === "string" && value.trim() !== "") {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : null;
  }
  return null;
}

function formatAmount({
  locale,
  maximumFractionDigits,
  minimumFractionDigits,
  value,
}: {
  locale?: string;
  maximumFractionDigits: number;
  minimumFractionDigits?: number;
  value: number;
}) {
  return new Intl.NumberFormat(locale, {
    maximumFractionDigits,
    minimumFractionDigits,
  }).format(value);
}

export function TokenBalance({
  amount,
  symbol,
  name,
  src,
  address,
  fiatValue,
  change,
  showLogo = true,
  showFiatValue = true,
  locale,
  maximumFractionDigits = 4,
  minimumFractionDigits,
  fallback = "--",
  logoProps,
  priceProps,
  className,
  amountClassName,
  fiatClassName,
}: TokenBalanceProps) {
  const parsedAmount = parseBalanceValue(amount);
  const hasFiatValue =
    showFiatValue && fiatValue !== null && fiatValue !== undefined && fiatValue !== "";

  return (
    <div className={cn("inline-flex items-center gap-3", className)}>
      {showLogo && (
        <TokenLogo
          address={address}
          name={name}
          src={src}
          symbol={symbol}
          {...logoProps}
        />
      )}

      <div className="grid min-w-0 gap-0.5">
        <div
          className={cn(
            "font-mono text-sm font-medium tabular-nums",
            amountClassName
          )}
        >
          {parsedAmount === null
            ? fallback
            : formatAmount({
                locale,
                maximumFractionDigits,
                minimumFractionDigits,
                value: parsedAmount,
              })}
          {symbol && <span className="ml-1 text-muted-foreground">{symbol}</span>}
        </div>

        {hasFiatValue && (
          <TokenPrice
            value={fiatValue}
            change={change}
            className={cn("text-xs text-muted-foreground", fiatClassName)}
            priceClassName="font-mono"
            {...priceProps}
          />
        )}
      </div>
    </div>
  );
}

"use client";

import { Tooltip as BaseTooltip } from "@base-ui/react/tooltip";
import type { ReactElement, ReactNode } from "react";
import { cn } from "@/lib/utils";

interface TooltipProps {
  children: ReactElement;
  content: ReactNode;
  delay?: number;
  side?: "top" | "right" | "bottom" | "left";
  className?: string;
}

export function Tooltip({
  children,
  content,
  delay = 200,
  side = "top",
  className,
}: TooltipProps) {
  if (!content) return children;

  return (
    <BaseTooltip.Root>
      <BaseTooltip.Trigger delay={delay} render={children} />
      <BaseTooltip.Portal>
        <BaseTooltip.Positioner side={side} sideOffset={6}>
          <BaseTooltip.Popup
            className={cn(
              "z-50 max-w-64 rounded-md border bg-popover px-2.5 py-1.5 text-xs text-popover-foreground shadow-md outline-none",
              "origin-[var(--transform-origin)] transition-[opacity,transform] duration-150",
              "data-[starting-style]:scale-95 data-[starting-style]:opacity-0",
              "data-[ending-style]:scale-95 data-[ending-style]:opacity-0",
              className
            )}
          >
            {content}
            <BaseTooltip.Arrow className="fill-popover" />
          </BaseTooltip.Popup>
        </BaseTooltip.Positioner>
      </BaseTooltip.Portal>
    </BaseTooltip.Root>
  );
}
